  'about.dsib.s6.h':    { en: 'Strong Work Ethic', ar: 'أخلاقيات عمل قوية' },
  'about.dsib.s6.p':    { en: 'Strong work ethic across academic subjects and extra-curricular activities.', ar: 'أخلاقيات عمل قوية عبر المواد الأكاديمية والأنشطة اللامنهجية.' },
