  /* ── POLICIES PAGE ───────────────────────────────────────── */
  'pol.notice.h':       { en: 'Our Commitment to Transparency', ar: 'التزامنا بالشفافية' },
  'pol.notice.p':       { en: 'Arab Unity School is committed to maintaining clear, fair, and regularly reviewed policies that protect students, support staff, and engage parents. All policies are KHDA-compliant and aligned with British educational standards. For full policy documents or queries, please contact <a href="mailto:info@arabunityschool.ae" style="color:#f0c040">info@arabunityschool.ae</a>.', ar: 'تلتزم مدرسة الوحدة العربية بالحفاظ على سياسات واضحة وعادلة وتُراجَع بانتظام لحماية الطلاب ودعم الموظفين وإشراك أولياء الأمور. جميع السياسات متوافقة مع هيئة المعرفة ومتوافقة مع المعايير التعليمية البريطانية. للحصول على وثائق السياسات الكاملة أو الاستفسارات، يرجى التواصل مع <a href="mailto:info@arabunityschool.ae" style="color:#f0c040">info@arabunityschool.ae</a>.' },
