  'pol.footnote.strong': { en: 'Note:', ar: 'ملاحظة:' },
  'pol.footnote.p':     { en: 'The summaries provided on this page are for general information purposes only. Complete details of all policies are available upon request. Please contact <a href="mailto:info@arabunityschool.ae" style="color:#2a7d3e;text-decoration:underline">info@arabunityschool.ae</a> to obtain full policy documents.', ar: 'الملخصات المقدمة في هذه الصفحة لأغراض المعلومات العامة فقط. التفاصيل الكاملة لجميع السياسات متاحة عند الطلب. يرجى التواصل مع <a href="mailto:info@arabunityschool.ae" style="color:#2a7d3e;text-decoration:underline">info@arabunityschool.ae</a> للحصول على وثائق السياسات الكاملة.' },
