/* =============================================================
   Core engine
============================================================= */
var AUS_LANG = (function() {
  'use strict';

  var STORAGE_KEY = 'aus_lang';
  var current = localStorage.getItem(STORAGE_KEY) || 'en';

  /* Get a translation string */
  function t(key, lang) {
    lang = lang || current;
    var entry = AUS_TRANSLATIONS[key];
    if (!entry) return '';
    return entry[lang] || entry['en'] || '';
  }

  /* Apply current language to entire document */
  function apply(lang) {
    current = lang;
    localStorage.setItem(STORAGE_KEY, lang);

    var html = document.documentElement;
    if (lang === 'ar') {
      html.setAttribute('lang', 'ar');
      html.setAttribute('dir', 'rtl');
      html.classList.add('rtl');
    } else {
      html.setAttribute('lang', 'en');
      html.setAttribute('dir', 'ltr');
      html.classList.remove('rtl');
    }

    /* Translate all data-i18n elements */
    document.querySelectorAll('[data-i18n]').forEach(function(el) {
      var key = el.getAttribute('data-i18n');
      var val = t(key, lang);
      if (val) el.innerHTML = val;
    });

    /* Translate placeholders */
    document.querySelectorAll('[data-i18n-placeholder]').forEach(function(el) {
      var key = el.getAttribute('data-i18n-placeholder');
      var val = t(key, lang);
      if (val) el.setAttribute('placeholder', val);
    });

    /* Translate aria-labels */
    document.querySelectorAll('[data-i18n-aria]').forEach(function(el) {
      var key = el.getAttribute('data-i18n-aria');
      var val = t(key, lang);
      if (val) el.setAttribute('aria-label', val);
    });

    /* Update toggle button text */
    document.querySelectorAll('.aus-lang-toggle').forEach(function(btn) {
      btn.textContent = lang === 'ar' ? 'English' : 'العربية';
      btn.setAttribute('lang', lang === 'ar' ? 'en' : 'ar');
    });

    /* Re-inject nav/footer with new language if nav.js already ran */
    if (window._ausNavInjectFn) window._ausNavInjectFn(lang);
  }

  /* Toggle between EN and AR */
  function toggle() {
    apply(current === 'en' ? 'ar' : 'en');
  }

  /* Run on DOM ready */
  function init() {
    apply(current);
  }

  /* Public API */
  return { t: t, apply: apply, toggle: toggle, init: init, current: function() { return current; } };

})();

/* Auto-init after DOM ready */
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', function() { AUS_LANG.init(); });
} else {
  AUS_LANG.init();
}
